const rawPath = $('Webhook').item.json.body.data.win.eventdata.targetObject || '';

if (!rawPath) {
	throw new Error('targetObject is empty');
}

const cleaned = rawPath.replace(/\\\\/g, '\\');
const match = cleaned.match(/^(HKU\\S-1-[^\\]+_Classes\\CLSID\\\{[0-9A-Fa-f-]{36}\})/i);

if (!match) {
	throw new Error('No CLSID parent found in: ' + rawPath);
}

return [
	{
		json: {
			targetPath: match[1]
		}
	}
];

